class Julian2DateUtil:
    @staticmethod
    def convert_to_date(year_digit: str, julian_day: str) -> 'Date':
        if len(year_digit) != 1 or not year_digit.isdigit():
            raise ValueError("Year digit must be a single digit string.")
        if len(julian_day) != 3 or not julian_day.isdigit():
            raise ValueError("Julian day must be a 3 character long string of digits.")

        year = 2000 + int(year_digit)
        day_of_year = int(julian_day)

        if day_of_year < 1 or day_of_year > 366:
            raise ValueError("Julian day must be between 1 and 366.")

        # Check for leap year
        is_leap_year = (year % 4 == 0 and year % 100 != 0) or (year % 400 == 0)
        if not is_leap_year and day_of_year == 366:
            raise ValueError("The year {} is not a leap year, cannot have 366 days.".format(year))

        # Month lengths
        month_lengths = [31, 28 + (1 if is_leap_year else 0), 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
        month = 0

        for length in month_lengths:
            if day_of_year <= length:
                break
            day_of_year -= length
            month += 1

        return Date(year, month + 1, day_of_year)
